// MARK: - Keychain Helper
class KeychainHelper {
    
    static let shared = KeychainHelper()
    private init() {}
    
    private let service = "com.myapp.authentication"
    private let authenticatedKey = "isAuthenticated"
    private let biometricEnabledKey = "biometricEnabled"
    
    func setAuthenticated(_ value: Bool) {
        let data = Data([value ? 1 : 0])
        save(data: data, forKey: authenticatedKey)
    }
    
    func isAuthenticated() -> Bool {
        guard let data = load(key: authenticatedKey), let byte = data.first else {
            return false
        }
        return byte == 1
    }
    
    func setBiometricEnabled(_ value: Bool) {
        let data = Data([value ? 1 : 0])
        save(data: data, forKey: biometricEnabledKey)
    }
    
    func isBiometricEnabled() -> Bool {
        guard let data = load(key: biometricEnabledKey), let byte = data.first else {
            return false
        }
        return byte == 1
    }
    
    func clearAuthentication() {
        delete(key: authenticatedKey)
    }
    
    private func save(data: Data, forKey key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key
        ]
        
        SecItemDelete(query as CFDictionary)
        
        var newQuery = query
        newQuery[kSecValueData as String] = data
        
        SecItemAdd(newQuery as CFDictionary, nil)
    }
    
    private func load(key: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        SecItemCopyMatching(query as CFDictionary, &result)
        return result as? Data
    }
    
    private func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Biometric Auth Manager
class BiometricAuthManager {
    
    static let shared = BiometricAuthManager()
    private init() {}
    
    enum BiometricType {
        case none
        case touchID
        case faceID
    }
    
    enum AuthError: Error, LocalizedError {
        case biometryNotAvailable
        case biometryNotEnrolled
        case biometryLockout
        case userCancel
        case userFallback
        case authenticationFailed
        case unknown(Error)
        
        var errorDescription: String? {
            switch self {
            case .biometryNotAvailable:
                return "Biometric authentication is not available on this device."
            case .biometryNotEnrolled:
                return "No biometric data is enrolled. Please set up Face ID or Touch ID in Settings."
            case .biometryLockout:
                return "Biometric authentication is locked due to too many failed attempts. Please use your passcode."
            case .userCancel:
                return "Authentication was cancelled."
            case .userFallback:
                return "User chose to enter password."
            case .authenticationFailed:
                return "Authentication failed. Please try again."
            case .unknown(let error):
                return error.localizedDescription
            }
        }
    }
    
    var biometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        
        switch context.biometryType {
        case .touchID:
            return .touchID
        case .faceID:
            return .faceID
        case .opticID:
            return .faceID
        @unknown default:
            return .none
        }
    }
    
    var biometricTypeString: String {
        switch biometricType {
        case .faceID: return "Face ID"
        case .touchID: return "Touch ID"
        case .none: return "Biometrics"
        }
    }
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    func authenticate(reason: String? = nil, completion: @escaping (Result<Bool, AuthError>) -> Void) {
        let context = LAContext()
        context.localizedFallbackTitle = "Enter Password"
        context.localizedCancelTitle = "Cancel"
        
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            if let laError = error as? LAError {
                let authError = mapLAError(laError)
                DispatchQueue.main.async {
                    completion(.failure(authError))
                }
            } else {
                DispatchQueue.main.async {
                    completion(.failure(.biometryNotAvailable))
                }
            }
            return
        }
        
        let authReason = reason ?? "Authenticate with \(biometricTypeString) to access your account"
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: authReason) { success, error in
            DispatchQueue.main.async {
                if success {
                    KeychainHelper.shared.setAuthenticated(true)
                    completion(.success(true))
                } else if let laError = error as? LAError {
                    completion(.failure(self.mapLAError(laError)))
                } else if let error = error {
                    completion(.failure(.unknown(error)))
                } else {
                    completion(.failure(.authenticationFailed))
                }
            }
        }
    }
    
    private func mapLAError(_ error: LAError) -> AuthError {
        switch error.code {
        case .biometryNotAvailable:
            return .biometryNotAvailable
        case .biometryNotEnrolled:
            return .biometryNotEnrolled
        case .biometryLockout:
            return .biometryLockout
        case .userCancel:
            return .userCancel
        case .userFallback:
            return .userFallback
        case .authenticationFailed:
            return .authenticationFailed
        default:
            return .unknown(error)
        }
    }
}

